from kafka import KafkaAdminClient, NewTopic
import argparse

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, config=config)
    admin_client.create_topics([topic])

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--topic', required=True, help='Name of the topic to create')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions for the topic')
    parser.add_argument('--replication', type=int, default=1, help='Replication factor for the topic')
    parser.add_argument('--config', nargs='*', help='Configuration settings for the topic in key=value format')

    args = parser.parse_args()

    config = {}
    if args.config:
        for item in args.config:
            key, value = item.split('=')
            config[key] = value

    admin_client = KafkaAdminClient(bootstrap_servers='localhost:9092')

    try:
        create_topic(admin_client, args.topic, args.partitions, args.replication, config)
        print(f'Topic {args.topic} created successfully.')
    except Exception as e:
        print(f'Error creating topic: {e}')
    finally:
        admin_client.close()

if __name__ == '__main__':
    main()